def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    skewness = np.mean((positive_bins - avg_capacity) ** 3) / (np.std(positive_bins) ** 3 + 1e-9) if positive_bins.size > 2 else 0.0
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = ((1 - ratio) ** 7) * 1.3 + 0.2
        elif 0.65 < ratio <= 0.9:
            score = np.exp(-ratio * 18) + 0.07
        elif 0.4 < ratio <= 0.65:
            temp = 0.0
            for k in range(1, 11):
                sign = 1 if k % 2 == 1 else -1
                term = sign * (ratio ** (k+3)) / (k * 1.2)
                temp += term
            score = abs(temp) + 0.1
        else:
            temp = 0.0
            for p in range(1, 15):
                weight = 1 / (p ** 1.5)
                sign = -1 if p % 2 == 0 else 1
                temp += sign * (ratio ** (p + 2)) * weight
            score = abs(temp) + 0.12
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 10):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2.2)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + variance:
                        influence *= 1.15
                    elif neighbor_capacity < avg_capacity - variance:
                        influence *= 0.85
                    neighbors_influence += influence
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.75) + (avg_capacity ** 0.25)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 3.5) * 0.5
        elif capacity > item * 1.8:
            penalty = 0.07
        if skewness > 0.5:
            if i % 5 == 0:
                penalty *= 1.3
            elif i % 3 == 0:
                penalty *= 0.85
        else:
            if i % 7 == 0:
                penalty *= 0.9
        if i % 2 == 0 and i % 3 == 0:
            score *= 0.75
            neighbors_influence *= 1.3
            penalty *= 1.15
        elif i % 4 == 0:
            score *= 1.15
            neighbors_influence *= 0.85
        elif i % 5 == 0:
            score *= 0.9
            neighbors_influence *= 1.05
        else:
            score *= 0.93
        priority = score + neighbors_influence / cap_factor + penalty
        if priority < 0:
            priority = 0
        if priority > 1.0:
            priority = np.log1p(priority) * 1.1
        else:
            priority = priority ** 1.2
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 5.5
    min_priority = np.min(priorities)
    max_priority = np.max(priorities)
    if max_priority - min_priority > 1e-9:
        for i in range(n):
            if i % 3 == 1:
                priorities[i] = (priorities[i] - min_priority) / (max_priority - min_priority) * 0.9 + 0.05
            else:
                priorities[i] = (priorities[i] - min_priority) / (max_priority - min_priority)
    return priorities
